import React, { useState } from 'react';
import { Card, Typography, Tag, Progress, Modal, Button, Space, Descriptions, Divider } from 'antd';
import {
    SoundOutlined,
    CalendarOutlined,
    StarOutlined,
    FileTextOutlined,
    WarningOutlined,
    BulbOutlined,
    EyeOutlined,
    CloseCircleOutlined
} from '@ant-design/icons';

const { Title, Text, Paragraph } = Typography;

const ConversationCard = ({ analysis }) => {
    const [modalVisible, setModalVisible] = useState(false);

    const getScoreColor = (score) => {
        if (score >= 4) return '#52c41a';
        if (score >= 3) return '#faad14';
        return '#ff4d4f';
    };

    const getScoreStatus = (score) => {
        if (score >= 4) return 'success';
        if (score >= 3) return 'warning';
        return 'exception';
    };

    const getTonalityColor = (tonality) => {
        switch (tonality) {
            case 'Позитивная':
            case 'Дружелюбная':
                return 'success';
            case 'Нейтральная':
                return 'warning';
            case 'Негативная':
                return 'error';
            default:
                return 'default';
        }
    };

    return (
        <>
            <Card
                hoverable
                style={{ height: '100%' }}
                actions={[
                    <Button type="link" icon={<EyeOutlined />} onClick={() => setModalVisible(true)}>
                        Подробнее
                    </Button>
                ]}
            >
                {/* Заголовок с файлом и датой */}
                <Space direction="vertical" size="small" style={{ width: '100%' }}>
                    <Space>
                        <SoundOutlined style={{ color: '#1890ff', fontSize: 20 }} />
                        <Text strong style={{ fontSize: 16 }}>
                            {analysis.fileName}
                        </Text>
                    </Space>

                    <Space>
                        <CalendarOutlined />
                        <Text type="secondary">{analysis.date}</Text>
                    </Space>
                </Space>

                <Divider style={{ margin: '12px 0' }} />

                {/* Оценки */}
                <div>
                    <Space direction="vertical" size="small" style={{ width: '100%' }}>
                        <div>
                            <Text strong>Общая оценка:</Text>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                <Progress
                                    percent={(analysis.scores.overall / 5) * 100}
                                    size="small"
                                    status={getScoreStatus(analysis.scores.overall)}
                                    format={() => `${analysis.scores.overall}/5`}
                                    style={{ flex: 1 }}
                                />
                            </div>
                        </div>

                        <div>
                            <Text type="secondary">Соблюдение скрипта:</Text>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                <Progress
                                    percent={(analysis.scores.scriptCompliance / 5) * 100}
                                    size="small"
                                    status={getScoreStatus(analysis.scores.scriptCompliance)}
                                    format={() => `${analysis.scores.scriptCompliance}/5`}
                                    style={{ flex: 1 }}
                                />
                            </div>
                        </div>

                        <div>
                            <Text type="secondary">Удовлетворенность:</Text>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                <Progress
                                    percent={(analysis.scores.satisfaction / 5) * 100}
                                    size="small"
                                    status={getScoreStatus(analysis.scores.satisfaction)}
                                    format={() => `${analysis.scores.satisfaction}/5`}
                                    style={{ flex: 1 }}
                                />
                            </div>
                        </div>

                        <div>
                            <Text type="secondary">Тональность:</Text>
                            <div>
                                <Tag color={getTonalityColor(analysis.scores.tonality)}>
                                    {analysis.scores.tonality}
                                </Tag>
                            </div>
                        </div>
                    </Space>
                </div>

                <Divider style={{ margin: '12px 0' }} />

                {/* Краткое резюме */}
                <Paragraph ellipsis={{ rows: 2 }} type="secondary" style={{ fontSize: 12 }}>
                    {analysis.summary}
                </Paragraph>
            </Card>

            {/* Модальное окно с деталями */}
            <Modal
                title={
                    <Space>
                        <StarOutlined style={{ color: '#faad14' }} />
                        <span>Детальный отчет по качеству обслуживания</span>
                    </Space>
                }
                open={modalVisible}
                onCancel={() => setModalVisible(false)}
                footer={[
                    <Button key="close" onClick={() => setModalVisible(false)}>
                        Закрыть
                    </Button>
                ]}
                width={700}
            >
                <Space direction="vertical" size="large" style={{ width: '100%' }}>
                    {/* Информация о файле */}
                    <Card size="small">
                        <Space direction="vertical">
                            <Space>
                                <SoundOutlined />
                                <Text strong>Файл:</Text>
                                <Text>{analysis.fileName}</Text>
                            </Space>
                            <Space>
                                <CalendarOutlined />
                                <Text strong>Дата:</Text>
                                <Text>{analysis.date}</Text>
                            </Space>
                        </Space>
                    </Card>

                    {/* Оценки детально */}
                    <Card title="📈 ОЦЕНКИ" size="small">
                        <Descriptions column={1}>
                            <Descriptions.Item label="⚠️ Общая оценка">
                                <Text strong style={{ color: getScoreColor(analysis.scores.overall) }}>
                                    {analysis.scores.overall}/5
                                </Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="📋 Соблюдение скрипта">
                                <Text>{analysis.scores.scriptCompliance}/5</Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="⭐️ Удовлетворенность">
                                <Text>{analysis.scores.satisfaction}/5</Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="😐 Тональность">
                                <Tag color={getTonalityColor(analysis.scores.tonality)}>
                                    {analysis.scores.tonality}
                                </Tag>
                            </Descriptions.Item>
                        </Descriptions>
                    </Card>

                    {/* Резюме */}
                    <Card title="📝 КРАТКОЕ РЕЗЮМЕ" size="small">
                        <Paragraph>{analysis.summary}</Paragraph>
                    </Card>

                    {/* Проблемы */}
                    <Card title="⚠️ КЛЮЧЕВЫЕ ПРОБЛЕМЫ" size="small">
                        <ul>
                            {analysis.problems.map((problem, idx) => (
                                <li key={idx}>{problem}</li>
                            ))}
                        </ul>
                    </Card>

                    {/* Рекомендации */}
                    <Card title="💡 РЕКОМЕНДАЦИИ" size="small">
                        <ul>
                            {analysis.recommendations.map((rec, idx) => (
                                <li key={idx}>{rec}</li>
                            ))}
                        </ul>
                    </Card>

                    <Text type="secondary" style={{ fontSize: 12, textAlign: 'center' }}>
                        🤖 Отчет сгенерирован автоматически
                    </Text>
                </Space>
            </Modal>
        </>
    );
};

export default ConversationCard;