import React, { useState } from 'react';
import { Layout, Typography, Card, Row, Col, Upload, message, Tabs, Space } from 'antd';
import { CloudUploadOutlined, FileTextOutlined, RobotOutlined } from '@ant-design/icons';
import FileUploader from './components/FileUploader';
import Dashboard from './components/Dashboard';
import './App.css';

const { Header, Content } = Layout;
const { Title } = Typography;

function App() {
  const [activeTab, setActiveTab] = useState('upload');
  const [uploadedFile, setUploadedFile] = useState(null);

  const handleUploadSuccess = (fileInfo) => {
    setUploadedFile(fileInfo);
    message.success('Файл успешно загружен! Результаты проверки появятся в дашборде');
    // Автоматически переключаемся на дашборд через 2 секунды
    setTimeout(() => {
      setActiveTab('dashboard');
    }, 2000);
  };

  const items = [
    {
      key: 'upload',
      label: (
        <Space>
          <CloudUploadOutlined />
          Загрузка разговора
        </Space>
      ),
      children: <FileUploader onUploadSuccess={handleUploadSuccess} />,
    },
    {
      key: 'dashboard',
      label: (
        <Space>
          <FileTextOutlined />
          Дашборт проверок
        </Space>
      ),
      children: <Dashboard lastUploadedFile={uploadedFile} />,
    },
  ];

  return (
    <Layout className="layout">
      <Header style={{ background: '#001529', padding: '0 50px' }}>
        <div style={{ display: 'flex', alignItems: 'center', height: '100%' }}>
          <RobotOutlined style={{ fontSize: 24, color: '#1890ff', marginRight: 12 }} />
          <Title level={3} style={{ color: 'white', margin: 0 }}>
            Система оценки качества обслуживания
          </Title>
        </div>
      </Header>
      <Content style={{ padding: '50px', background: '#f0f2f5' }}>
        <div style={{ maxWidth: 1400, margin: '0 auto' }}>
          <Tabs activeKey={activeTab} onChange={setActiveTab} items={items} size="large" />
        </div>
      </Content>
    </Layout>
  );
}

export default App;