import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Statistic, Empty, Typography, Tag, Space, Button, Modal } from 'antd';
import {
    FileTextOutlined,
    CheckCircleOutlined,
    WarningOutlined,
    StarOutlined,
    SmileOutlined,
    MehOutlined,
    FrownOutlined,
    EyeOutlined
} from '@ant-design/icons';
import ConversationCard from './ConversationCard';

const { Title, Text } = Typography;

const Dashboard = ({ lastUploadedFile }) => {
    const [analyses, setAnalyses] = useState([]);
    const [stats, setStats] = useState({
        total: 0,
        averageScore: 0,
        excellentCount: 0,
        needsImprovement: 0
    });

    // Хардкодные данные для демонстрации
    const hardcodedAnalyses = [
        {
            id: 1,
            fileName: "В 1712 году столица.mp3",
            date: "07.04.2026 16:41",
            scores: {
                overall: 1,
                scriptCompliance: 0,
                satisfaction: 1,
                tonality: "Нейтральная"
            },
            summary: "диалог не состоялся, была представлена только историческая информация без контекста",
            problems: [
                "отсутствие диалога",
                "нет взаимодействия с клиентом"
            ],
            recommendations: [
                "уточнить запрос клиента",
                "провести полноценную беседу"
            ]
        },
        {
            id: 2,
            fileName: "консультация_по_тарифу.mp3",
            date: "06.04.2026 14:23",
            scores: {
                overall: 4,
                scriptCompliance: 5,
                satisfaction: 4,
                tonality: "Позитивная"
            },
            summary: "Оператор профессионально проконсультировал клиента по тарифам, помог выбрать оптимальный вариант. Клиент остался доволен обслуживанием.",
            problems: [
                "небольшая задержка с ответом на 2 вопрос"
            ],
            recommendations: [
                "улучшить знание акционных предложений",
                "активнее предлагать дополнительные услуги"
            ]
        },
        {
            id: 3,
            fileName: "рекламация_по_качеству.mp3",
            date: "05.04.2026 11:15",
            scores: {
                overall: 3,
                scriptCompliance: 3,
                satisfaction: 2,
                tonality: "Негативная"
            },
            summary: "Клиент был недоволен качеством услуги, оператор попытался решить проблему, но не проявил достаточно эмпатии.",
            problems: [
                "не извинился за доставленные неудобства",
                "не предложил компенсацию",
                "говорил шаблонными фразами"
            ],
            recommendations: [
                "пройти тренинг по работе с возражениями",
                "использовать технику 'лестница эмпатии'",
                "предлагать конкретные решения проблемы"
            ]
        },
        {
            id: 4,
            fileName: "подключение_услуги.mp3",
            date: "04.04.2026 09:52",
            scores: {
                overall: 5,
                scriptCompliance: 5,
                satisfaction: 5,
                tonality: "Дружелюбная"
            },
            summary: "Отличный диалог! Оператор полностью соблюдал скрипт, проявил эмпатию, подробно объяснил условия подключения. Клиент выразил благодарность.",
            problems: [
                "нет проблем - диалог идеальный"
            ],
            recommendations: [
                "продолжать в том же духе",
                "делиться опытом с коллегами"
            ]
        },
        {
            id: 5,
            fileName: "смена_тарифного_плана.mp3",
            date: "03.04.2026 16:30",
            scores: {
                overall: 4,
                scriptCompliance: 4,
                satisfaction: 4,
                tonality: "Позитивная"
            },
            summary: "Оператор быстро и профессионально сменил тарифный план, ответил на все вопросы клиента. Клиент удовлетворен скоростью обслуживания.",
            problems: [
                "не уточнил, удобно ли клиенту разговаривать"
            ],
            recommendations: [
                "всегда начинать диалог с вопроса о комфортном времени",
                "использовать технику активного слушания"
            ]
        }
    ];

    useEffect(() => {
        // Загружаем сохраненные анализы из localStorage
        const savedAnalyses = localStorage.getItem('conversationAnalyses');
        let allAnalyses = hardcodedAnalyses;

        if (savedAnalyses) {
            const parsedSaved = JSON.parse(savedAnalyses);
            allAnalyses = [...parsedSaved, ...hardcodedAnalyses];
        }

        // Если есть новый загруженный файл, добавляем его в начало
        if (lastUploadedFile && !allAnalyses.find(a => a.id === lastUploadedFile.id)) {
            allAnalyses = [lastUploadedFile, ...allAnalyses];
        }

        setAnalyses(allAnalyses);
        calculateStats(allAnalyses);
    }, [lastUploadedFile]);

    const calculateStats = (data) => {
        const total = data.length;
        const totalScore = data.reduce((sum, item) => sum + item.scores.overall, 0);
        const averageScore = total > 0 ? (totalScore / total).toFixed(1) : 0;
        const excellentCount = data.filter(item => item.scores.overall >= 4).length;
        const needsImprovement = data.filter(item => item.scores.overall <= 2).length;

        setStats({
            total,
            averageScore,
            excellentCount,
            needsImprovement
        });
    };

    const getScoreColor = (score) => {
        if (score >= 4) return '#52c41a';
        if (score >= 3) return '#faad14';
        return '#ff4d4f';
    };

    const getTonalityIcon = (tonality) => {
        switch (tonality) {
            case 'Позитивная':
            case 'Дружелюбная':
                return <SmileOutlined style={{ color: '#52c41a' }} />;
            case 'Нейтральная':
                return <MehOutlined style={{ color: '#faad14' }} />;
            case 'Негативная':
                return <FrownOutlined style={{ color: '#ff4d4f' }} />;
            default:
                return <MehOutlined />;
        }
    };

    return (
        <div>
            <Title level={3} style={{ marginBottom: 24 }}>
                Дашборт результатов проверок
            </Title>

            {/* Статистика */}
            <Row gutter={16} style={{ marginBottom: 24 }}>
                <Col span={6}>
                    <Card>
                        <Statistic
                            title="Всего проверок"
                            value={stats.total}
                            prefix={<FileTextOutlined />}
                            valueStyle={{ color: '#1890ff' }}
                        />
                    </Card>
                </Col>
                <Col span={6}>
                    <Card>
                        <Statistic
                            title="Средняя оценка"
                            value={stats.averageScore}
                            suffix="/5"
                            prefix={<StarOutlined />}
                            valueStyle={{ color: getScoreColor(stats.averageScore) }}
                        />
                    </Card>
                </Col>
                <Col span={6}>
                    <Card>
                        <Statistic
                            title="Отличные проверки (4-5)"
                            value={stats.excellentCount}
                            prefix={<CheckCircleOutlined />}
                            valueStyle={{ color: '#52c41a' }}
                        />
                    </Card>
                </Col>
                <Col span={6}>
                    <Card>
                        <Statistic
                            title="Требуют улучшения (1-2)"
                            value={stats.needsImprovement}
                            prefix={<WarningOutlined />}
                            valueStyle={{ color: '#ff4d4f' }}
                        />
                    </Card>
                </Col>
            </Row>

            {/* Список карточек проверок */}
            <Row gutter={[16, 16]}>
                {analyses.length > 0 ? (
                    analyses.map((analysis) => (
                        <Col xs={24} lg={12} xl={8} key={analysis.id}>
                            <ConversationCard analysis={analysis} />
                        </Col>
                    ))
                ) : (
                    <Col span={24}>
                        <Empty description="Нет результатов проверок" />
                    </Col>
                )}
            </Row>
        </div>
    );
};

export default Dashboard;