import React, { useState } from 'react';
import { Card, Upload, Button, message, Progress, Space, Typography, Alert } from 'antd';
import { InboxOutlined, UploadOutlined, CheckCircleOutlined } from '@ant-design/icons';
import axios from 'axios';

const { Dragger } = Upload;
const { Paragraph, Text } = Typography;

const FileUploader = ({ onUploadSuccess }) => {
    const [uploading, setUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const [fileList, setFileList] = useState([]);

    // Функция для загрузки на S3 (Яндекс Облако)
    const uploadToYandexS3 = async (file) => {
        // ⚠️ ВАЖНО: Здесь нужно реализовать реальную загрузку в S3
        // Сейчас это симуляция для демонстрации

        return new Promise((resolve, reject) => {
            // Симулируем загрузку на S3
            let progress = 0;
            const interval = setInterval(() => {
                progress += 10;
                setUploadProgress(progress);

                if (progress >= 100) {
                    clearInterval(interval);

                    // Симулируем успешную загрузку
                    const s3Response = {
                        success: true,
                        fileUrl: `https://storage.yandexcloud.net/bucket-name/${file.name}`,
                        fileKey: `conversations/${Date.now()}_${file.name}`,
                        bucket: 'your-bucket-name'
                    };

                    resolve(s3Response);
                }
            }, 200);
        });
    };

    // Функция для отправки на анализ (вызов API)
    const analyzeConversation = async (file, s3Info) => {
        // Симулируем вызов API для анализа разговора
        // В реальном проекте здесь был бы POST запрос к вашему бэкенду

        return new Promise((resolve) => {
            setTimeout(() => {
                // Имитируем ответ API с результатами проверки
                const analysisResult = {
                    id: Date.now(),
                    fileName: file.name,
                    date: new Date().toLocaleString('ru-RU'),
                    scores: {
                        overall: Math.floor(Math.random() * 3) + 3, // 3-5 из 5
                        scriptCompliance: Math.floor(Math.random() * 3) + 2,
                        satisfaction: Math.floor(Math.random() * 3) + 2,
                        tonality: ['Позитивная', 'Нейтральная', 'Негативная', 'Дружелюбная'][Math.floor(Math.random() * 4)]
                    },
                    summary: getRandomSummary(),
                    problems: getRandomProblems(),
                    recommendations: getRandomRecommendations(),
                    s3Url: s3Info.fileUrl,
                    timestamp: Date.now()
                };

                resolve(analysisResult);
            }, 1500);
        });
    };

    // Вспомогательные функции для генерации случайных результатов
    const getRandomSummary = () => {
        const summaries = [
            'Оператор профессионально обработал запрос клиента, предоставил полную информацию по вопросу. Диалог проходил в конструктивном ключе.',
            'Оператор не полностью соблюдал скрипт обслуживания, но смог решить проблему клиента. Рекомендуется улучшить знание продукта.',
            'Отличный диалог! Оператор проявил эмпатию, быстро решил проблему клиента. Клиент выразил благодарность.',
            'Оператор допустил ошибки в скрипте, не уточнил детали запроса. Клиент остался не полностью удовлетворен обслуживанием.',
            'Диалог проведен на высоком уровне, оператор использовал все необходимые фразы приветствия и прощания, активно слушал клиента.'
        ];
        return summaries[Math.floor(Math.random() * summaries.length)];
    };

    const getRandomProblems = () => {
        const problemsList = [
            ['Не использовано приветствие по имени', 'Прервал клиента', 'Не предложил дополнительную помощь'],
            ['Отсутствует благодарность в конце диалога', 'Долгое ожидание ответа', 'Не уточнил контактные данные'],
            ['Нет проблем - диалог идеальный'],
            ['Не соблюден скрипт продажи', 'Нет активных вопросов к клиенту', 'Не проявлена эмпатия'],
            ['Не предоставлена полная информация о продукте', 'Не уточнены потребности клиента']
        ];
        return problemsList[Math.floor(Math.random() * problemsList.length)];
    };

    const getRandomRecommendations = () => {
        const recommendationsList = [
            ['Рекомендуется пройти тренинг по активному слушанию', 'Использовать скрипт разговора', 'Практиковать эмпатию'],
            ['Улучшить знание продуктовой линейки', 'Использовать технику перефразирования', 'Записывать ключевую информацию'],
            ['Продолжать в том же духе', 'Делиться опытом с коллегами'],
            ['Проработать возражения клиентов', 'Изучить чек-лист качественного обслуживания', 'Смотреть эталонные звонки'],
            ['Использовать паузы для сбора мыслей', 'Больше уточняющих вопросов', 'Фиксировать договоренности']
        ];
        return recommendationsList[Math.floor(Math.random() * recommendationsList.length)];
    };

    const handleUpload = async () => {
        if (fileList.length === 0) {
            message.warning('Пожалуйста, выберите файл для загрузки');
            return;
        }

        const file = fileList[0].originFileObj;

        setUploading(true);
        setUploadProgress(0);

        try {
            // Шаг 1: Загрузка на S3
            message.loading('Загрузка файла на S3...', 0);
            const s3Result = await uploadToYandexS3(file);
            message.destroy();
            message.success('Файл успешно загружен в S3 бакет');

            // Шаг 2: Отправка на анализ
            message.loading('Анализ разговора...', 0);
            const analysisResult = await analyzeConversation(file, s3Result);
            message.destroy();
            message.success('Анализ разговора завершен');

            // Шаг 3: Сохранение результатов в localStorage
            const existingResults = JSON.parse(localStorage.getItem('conversationAnalyses') || '[]');
            existingResults.unshift(analysisResult);
            localStorage.setItem('conversationAnalyses', JSON.stringify(existingResults));

            // Шаг 4: Уведомляем родительский компонент
            onUploadSuccess(analysisResult);

            setFileList([]);
        } catch (error) {
            message.error('Ошибка при загрузке или анализе файла');
            console.error('Error:', error);
        } finally {
            setUploading(false);
            setUploadProgress(0);
        }
    };

    const uploadProps = {
        onRemove: () => {
            setFileList([]);
        },
        beforeUpload: (file) => {
            const isValidType = file.type === 'audio/mpeg' ||
                file.type === 'audio/wav' ||
                file.type === 'audio/mp3' ||
                file.name.endsWith('.mp3') ||
                file.name.endsWith('.wav') ||
                file.name.endsWith('.m4a');

            if (!isValidType) {
                message.error('Можно загружать только аудио файлы (mp3, wav, m4a)');
                return false;
            }

            const isLt50M = file.size / 1024 / 1024 < 50;
            if (!isLt50M) {
                message.error('Файл должен быть меньше 50MB');
                return false;
            }

            setFileList([file]);
            return false;
        },
        fileList,
    };

    return (
        <Card
            title="Загрузка аудиозаписи разговора"
            style={{ marginTop: 20 }}
            extra={<Text type="secondary">Поддерживаются форматы: MP3, WAV, M4A (до 50MB)</Text>}
        >
            <Dragger {...uploadProps} style={{ padding: '20px' }}>
                <p className="ant-upload-drag-icon">
                    <InboxOutlined />
                </p>
                <p className="ant-upload-text">Нажмите или перетащите файл в эту область</p>
                <p className="ant-upload-hint">
                    Загрузите аудиозапись разговора оператора с клиентом для автоматической оценки качества
                </p>
            </Dragger>

            {uploading && (
                <div style={{ marginTop: 20 }}>
                    <Progress percent={uploadProgress} status="active" />
                    <Text type="secondary">
                        {uploadProgress < 100 ? 'Загрузка на S3...' : 'Анализ разговора...'}
                    </Text>
                </div>
            )}

            <div style={{ marginTop: 20, textAlign: 'center' }}>
                <Button
                    type="primary"
                    icon={<UploadOutlined />}
                    onClick={handleUpload}
                    loading={uploading}
                    disabled={fileList.length === 0}
                    size="large"
                >
                    Загрузить и проанализировать
                </Button>
            </div>

            <Alert
                message="Информация о загрузке"
                description="Файл будет загружен в Yandex Cloud S3 бакет и автоматически проанализирован. Результаты появятся в дашборде."
                type="info"
                showIcon
                style={{ marginTop: 20 }}
            />
        </Card>
    );
};

export default FileUploader;